6 #ifndef MATERIAL_H
7 #define MATERIAL_H
8 
9 #include <string>
10 #include <unordered_map>
11 #include <memory>
12 
13 #include "Rendering/Shaders/ShaderProgram.h"
14 
16 struct IMaterialProperty{
23     virtual void apply(ShaderProgram& shader, const std::string& name, bool assumeBound) = 0;
27     virtual ~IMaterialProperty() = default;
28 };
29 
31 template <typename T>
32 struct MaterialProperty : public IMaterialProperty{
33     T value;
38     MaterialProperty(T val) : value(val) {};
39 
40     void apply(ShaderProgram& shader, const std::string& name, bool assumeBound) override{
41         Uniform<T> uni;
42         uni.set(this->value);
43         if(assumeBound){
44             shader.setUniformFast(name,uni);
45         }else{
46             shader.setUniform(name,uni);
47         }
48     }
49 };
50 
52 class Material{
53     private:
54         std::shared_ptr<ShaderProgram> programObjPtr;
55         std::unordered_map<std::string, std::shared_ptr<IMaterialProperty>> properties;
56         bool castsShadowsFlag = true;
57         bool receivesShadowsFlag = true;
58     public:
63         Material(std::shared_ptr<ShaderProgram> program) : programObjPtr(program) {
64             if(program){
65                 if(program->getID() == 0){
66                     if(program->compile() == 0){
67                         LogBot.Log(LOG_ERRO, "Failed to Compile Shader / Shader Program: \n\n%s",program->getLog().c_str());
68                     }
69                 }
70             }
71 
72             set<int>("u_receiveShadows", receivesShadowsFlag ? 1 : 0);
73         };
77         virtual ~Material(){};
78 
79         template<typename T>
80         bool set(const std::string& name, T value){
81             auto it = properties.find(name);
82             if(it != properties.end()){
83                 auto existing = std::dynamic_pointer_cast<MaterialProperty<T>>(it->second);
84                 if(existing){
85                     existing->value = value;
86                     return true;
87                 }
88             }
89 
90             properties[name] = std::make_shared<MaterialProperty<T>>(value);
91             return true;
92         }
93 
94         virtual void bind(){
95             if(!programObjPtr || programObjPtr->getID() == 0){
96                 return;
97             }
98             programObjPtr->bind();
99 
100             for(auto const& [name, prop] : properties){
101                 prop->apply(*programObjPtr, name, true);
102             }
103         };
104 
105         void unbind(){
106             if(programObjPtr){
107                 programObjPtr->unbind();
108             }
109         }
110 
111         std::shared_ptr<ShaderProgram> getShader(){
112             return this->programObjPtr;
113         }
114 
115         void setShader(std::shared_ptr<ShaderProgram> program){
116             programObjPtr = program;
117             if(programObjPtr && programObjPtr->getID() == 0){
118                 if(programObjPtr->compile() == 0){
119                     LogBot.Log(LOG_ERRO, "Failed to Compile Shader / Shader Program: \n\n%s", programObjPtr->getLog().c_str());
120                 }
121             }
122         }
123 
124         void setCastsShadows(bool value){ castsShadowsFlag = value; }
125         bool castsShadows() const { return castsShadowsFlag; }
126 
127         void setReceivesShadows(bool value){
128             receivesShadowsFlag = value;
129             set<int>("u_receiveShadows", receivesShadowsFlag ? 1 : 0);
130         }
131         bool receivesShadows() const { return receivesShadowsFlag; }
132 
133         static std::shared_ptr<Material> Copy(std::shared_ptr<Material> material){
134             if(!material) return nullptr;
135             auto n_material = std::make_shared<Material>(material->getShader());
136             n_material->properties = material->properties;
137             return n_material;
138         }
139 
140         template<typename T>
141         static std::shared_ptr<T> GetAs(std::shared_ptr<Material> matPtr){
142             return std::dynamic_pointer_cast<T>(matPtr);
143         }
144 };
145 
146 typedef std::shared_ptr<Material> PMaterial;
